func testAccBiglakeHiveHiveTable_biglakeHiveTableExample(context map[string]interface{}) string {
	return acctest.Nprintf(`
terraform {
  required_providers {
    google = {
      source = "hashicorp/google-beta"
    }
  }
}

resource "google_storage_bucket" "bucket" {
  name          = "%{bucket_name}"
  location      = "us-central1"
  force_destroy = true
  uniform_bucket_level_access = true
}

resource "google_biglake_hive_catalog" "catalog" {
  name             = "tf_test_catalog%{random_suffix}"
  primary_location = "us-central1"
  location_uri     = "gs://${google_storage_bucket.bucket.name}"
}

resource "google_biglake_hive_database" "database" {
  catalog      = google_biglake_hive_catalog.catalog.name
  name         = "tf_test_database%{random_suffix}"
  location_uri = "gs://${google_storage_bucket.bucket.name}"
}

resource "google_biglake_hive_table" "my_hive_table" {
  catalog  = google_biglake_hive_catalog.catalog.name
  database = google_biglake_hive_database.database.name
  name     = "tf_test_table%{random_suffix}"

  description = "%{description}"
  storage_descriptor {
    %{columns}
    input_format         = "org.apache.hadoop.mapred.TextInputFormat"
    output_format        = "org.apache.hadoop.hive.ql.io.HiveIgnoreKeyTextOutputFormat"
    compressed           = %{compressed}
    num_buckets          = %{num_buckets}
    bucket_cols          = %{bucket_cols}
    %{sort_cols}
    %{skewed_info}
    serde_info {
      name               = "LazySimpleSerDe"
      serialization_lib  = "org.apache.hadoop.hive.serde2.lazy.LazySimpleSerDe"
    }
    parameters           = %{parameters}
    stored_as_sub_dirs   = %{stored_as_sub_dirs}
  }
  %{partition_keys}
  parameters = %{parameters}
}
`, context)
}

func testAccCheckBiglakeHiveHiveTableDestroyProducer(t *testing.T) func(s *terraform.State) error {
	return func(s *terraform.State) error {
		for name, rs := range s.RootModule().Resources {
			if rs.Type != "google_biglake_hive_table" {
				continue
			}
			if strings.HasPrefix(name, "data.") {
				continue
			}

			config := acctest.GoogleProviderConfig(t)
			url, err := tpgresource.ReplaceVarsForTest(config, rs, transport_tpg.BaseUrl(biglakehive.Product, config)+"hive/v1beta/projects/{{project}}/catalogs/{{catalog}}/databases/{{database}}/tables/{{name}}")
			if err != nil {
				return err
			}

			billingProject := ""

			if config.BillingProject != "" {
				billingProject = config.BillingProject
			}

			_, err = transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
				Config:    config,
				Method:    "GET",
				Project:   billingProject,
				RawURL:    url,
				UserAgent: config.UserAgent,
			})
			if err == nil {
				return fmt.Errorf("BiglakeHiveHiveTable still exists at %s", url)
			}
		}

		return nil
	}
}
